1	// ============================================
2	// SMART SPAM DETECTOR — GMAIL CONTENT SCRIPT
3	// Floating "Check Spam" button on Gmail emails
4	// ============================================
5	
6	(function () {
7	  "use strict";
8	
9	  const BUTTON_ID = "ssd-floating-btn";
10	  const RESULT_ID = "ssd-result-overlay";
11	  let isAnalyzing = false;
12	  let lastUrl = "";
13	
14	  // ---- MAIN LOOP: Poll for email view changes ----
15	  // Gmail is a SPA — URL changes when opening emails but page doesn't reload
16	  setInterval(checkForEmailView, 1000);
17	
18	  function checkForEmailView() {
19	    const currentUrl = window.location.href;
20	
21	    // Gmail email view URLs contain a message ID hash fragment
22	    // Inbox: https://mail.google.com/mail/u/0/#inbox
23	    // Email: https://mail.google.com/mail/u/0/#inbox/FMfcgzQXKJWPsNqfnqdnVHLjTZBRhBjD
24	    const isEmailOpen = isEmailViewOpen();
25	
26	    const btn = document.getElementById(BUTTON_ID);
27	
28	    if (isEmailOpen && !btn) {
29	      injectFloatingButton();
30	    } else if (!isEmailOpen && btn) {
31	      btn.remove();
32	      const result = document.getElementById(RESULT_ID);
33	      if (result) result.remove();
34	    }
35	
36	    lastUrl = currentUrl;
37	  }
38	
39	  // ---- DETECT IF AN EMAIL IS OPEN ----
40	  function isEmailViewOpen() {
41	    // Method 1: Check URL pattern — email URLs have a longer hash
42	    const hash = window.location.hash;
43	    // Email view hashes look like #inbox/MESSAGE_ID or #sent/MESSAGE_ID etc.
44	    // They have at least 2 path segments after #
45	    const hashParts = hash.replace("#", "").split("/");
46	    if (hashParts.length >= 2 && hashParts[1].length > 5) {
47	      return true;
48	    }
49	
50	    // Method 2: Check for email body elements in DOM
51	    if (document.querySelector('div.a3s')) return true;
52	    if (document.querySelector('[data-message-id]')) return true;
53	    if (document.querySelector('div[role="list"] div[role="listitem"]')) return true;
54	
55	    // Method 3: Check for conversation view indicators
56	    if (document.querySelector('table.Bs > tr > td > div[class*="a3s"]')) return true;
57	    if (document.querySelector('.ii.gt')) return true;
58	    if (document.querySelector('.nH.if')) return true;
59	
60	    return false;
61	  }
62	
63	  // ---- INJECT FLOATING BUTTON ----
64	  function injectFloatingButton() {
65	    // Don't duplicate
66	    if (document.getElementById(BUTTON_ID)) return;
67	
68	    const btn = document.createElement("div");
69	    btn.id = BUTTON_ID;
70	    btn.innerHTML = `
71	      <div class="ssd-fab-inner">
72	        <span class="ssd-fab-shield">🛡️</span>
73	        <span class="ssd-fab-label">Check Spam</span>
74	      </div>
75	    `;
76	    btn.addEventListener("click", handleCheckSpam);
77	    document.body.appendChild(btn);
78	  }
79	
80	  // ---- HANDLE CHECK SPAM ----
81	  async function handleCheckSpam() {
82	    if (isAnalyzing) return;
83	    isAnalyzing = true;
84	
85	    const btn = document.getElementById(BUTTON_ID);
86	    if (btn) {
87	      btn.classList.add("ssd-loading");
88	      btn.querySelector(".ssd-fab-label").textContent = "Scanning...";
89	    }
90	
91	    // Remove previous result
92	    const prevResult = document.getElementById(RESULT_ID);
93	    if (prevResult) prevResult.remove();
94	
95	    try {
96	      const emailText = extractEmailText();
97	
98	      if (!emailText || emailText.length < 5) {
99	        showResultOverlay({
100	          prediction: "error",
101	          confidence: 0,
102	          trigger_words: [],
103	        }, "Could not extract email text. Try the popup instead.");
104	        return;
105	      }
106	
107	      // Detect Gmail context clues
108	      const gmailSpamLabel = isInSpamFolder();
109	      const senderInfo = extractSender();
110	
111	      // Send to background script → API
112	      const response = await chrome.runtime.sendMessage({
113	        type: "ANALYZE_EMAIL",
114	        text: emailText,
115	        gmail_spam: gmailSpamLabel,
116	        sender: senderInfo,
117	      });
118	
119	      if (response && response.success) {
120	        showResultOverlay(response.data);
121	        // Also save to history
122	        saveToHistory(emailText, response.data);
123	      } else {
124	        showResultOverlay(
125	          { prediction: "error", confidence: 0, trigger_words: [] },
126	          (response && response.error) || "API connection failed. Check Settings."
127	        );
128	      }
129	    } catch (err) {
130	      showResultOverlay(
131	        { prediction: "error", confidence: 0, trigger_words: [] },
132	        "Extension error: " + err.message
133	      );
134	    } finally {
135	      isAnalyzing = false;
136	      if (btn) {
137	        btn.classList.remove("ssd-loading");
138	        btn.querySelector(".ssd-fab-label").textContent = "Check Spam";
139	      }
140	    }
141	  }
142	
143	  // ---- DETECT GMAIL SPAM FOLDER ----
144	  function isInSpamFolder() {
145	    // Check URL
146	    const hash = window.location.hash.toLowerCase();
147	    if (hash.includes("spam")) return true;
148	
149	    // Check for spam label in the email header
150	    const labels = document.querySelectorAll('.ar .at, .aY2 .at, .at');
151	    for (const label of labels) {
152	      const text = (label.textContent || "").toLowerCase().trim();
153	      if (text === "spam" || text === "junk") return true;
154	    }
155	
156	    // Check for Gmail's spam warning banner
157	    const warningText = document.querySelector('.bAs, .gE');
158	    if (warningText) {
159	      const wt = (warningText.textContent || "").toLowerCase();
160	      if (wt.includes("spam") || wt.includes("phishing") || wt.includes("suspicious")) return true;
161	    }
162	
163	    return false;
164	  }
165	
166	  // ---- EXTRACT SENDER INFO ----
167	  function extractSender() {
168	    // Try to get sender email from header
169	    const senderEl = document.querySelector('.gD[email], [email]');
170	    if (senderEl) return senderEl.getAttribute("email") || "";
171	
172	    // Try from "from" display
173	    const fromEl = document.querySelector('.go, .gD');
174	    if (fromEl) return (fromEl.textContent || "").trim();
175	
176	    return "";
177	  }
178	
179	  // ---- EXTRACT EMAIL TEXT ----
180	  function extractEmailText() {
181	    let parts = [];
182	
183	    // Grab the email subject (strong spam signal)
184	    const subjectEl = document.querySelector('h2[data-thread-perm-id]') ||
185	                      document.querySelector('div[role="main"] h2') ||
186	                      document.querySelector('.hP');
187	    if (subjectEl) {
188	      const subject = (subjectEl.innerText || "").trim();
189	      if (subject) parts.push("Subject: " + subject);
190	    }
191	
192	    // Gmail spam/phishing warning banner
193	    const warningBanner = document.querySelector('.bAs');
194	    if (warningBanner) {
195	      parts.push(warningBanner.innerText || "");
196	    }
197	
198	    // Strategy 1: Gmail message body (.a3s.aiL or .a3s) — most reliable
199	    const bodies = document.querySelectorAll("div.a3s.aiL, div.a3s");
200	    if (bodies.length > 0) {
201	      const bodyText = Array.from(bodies)
202	        .map((el) => el.innerText || el.textContent)
203	        .join("\n\n")
204	        .trim();
205	      if (bodyText.length > 5) parts.push(bodyText);
206	    }
207	
208	    // Strategy 2: .ii.gt class (Gmail message body wrapper)
209	    if (parts.length <= 1) {
210	      const gtBodies = document.querySelectorAll(".ii.gt");
211	      if (gtBodies.length > 0) {
212	        const gtText = Array.from(gtBodies)
213	          .map((el) => el.innerText || el.textContent)
214	          .join("\n\n")
215	          .trim();
216	        if (gtText.length > 5) parts.push(gtText);
217	      }
218	    }
219	
220	    // Strategy 3: data-message-id containers
221	    if (parts.length <= 1) {
222	      const msgContainers = document.querySelectorAll("[data-message-id]");
223	      if (msgContainers.length > 0) {
224	        const msgText = Array.from(msgContainers)
225	          .map((el) => el.innerText || el.textContent)
226	          .join("\n\n")
227	          .trim();
228	        if (msgText.length > 5) parts.push(msgText);
229	      }
230	    }
231	
232	    // Strategy 4: Fallback — main content area
233	    if (parts.length <= 1) {
234	      const mainArea = document.querySelector('div[role="main"]');
235	      if (mainArea) {
236	        const mainText = (mainArea.innerText || "").trim();
237	        if (mainText.length > 10) parts.push(mainText);
238	      }
239	    }
240	
241	    let fullText = parts.join("\n\n").trim();
242	
243	    // Strip common Gmail UI noise
244	    const uiNoise = [
245	      "Reply", "Forward", "Report spam", "Report not spam", "Delete forever",
246	      "Not spam", "Compose", "Inbox", "Starred", "Snoozed", "Sent", "Drafts",
247	      "More", "Labels", "Manage labels", "Create new label", "Show details",
248	      "Hide details", "to me", "Unsubscribe"
249	    ];
250	    for (const noise of uiNoise) {
251	      fullText = fullText.replace(new RegExp("^" + noise + "$", "gm"), "");
252	    }
253	
254	    // Clean up extra whitespace
255	    fullText = fullText.replace(/\n{3,}/g, "\n\n").trim();
256	
257	    return fullText.substring(0, 5000) || null;
258	  }
259	
260	  // ---- SHOW RESULT OVERLAY ----
261	  function showResultOverlay(data, errorMsg) {
262	    const existing = document.getElementById(RESULT_ID);
263	    if (existing) existing.remove();
264	
265	    const isSpam = data.prediction === "spam";
266	    const isError = data.prediction === "error";
267	
268	    const overlay = document.createElement("div");
269	    overlay.id = RESULT_ID;
270	    overlay.className = `ssd-overlay ${isError ? "ssd-error" : isSpam ? "ssd-spam" : "ssd-genuine"}`;
271	
272	    let triggerHTML = "";
273	    if (data.trigger_words && data.trigger_words.length > 0) {
274	      triggerHTML = `
275	        <div class="ssd-overlay-triggers">
276	          <span class="ssd-trigger-title">⚠️ Trigger words:</span>
277	          <div class="ssd-trigger-list">
278	            ${data.trigger_words.map((w) => `<span class="ssd-tag">${w}</span>`).join("")}
279	          </div>
280	        </div>`;
281	    }
282	
283	    overlay.innerHTML = `
284	      <button class="ssd-overlay-close" title="Close">&times;</button>
285	      <div class="ssd-overlay-header">
286	        <span class="ssd-overlay-icon">${isError ? "⚠️" : isSpam ? "🚨" : "✅"}</span>
287	        <div>
288	          <div class="ssd-overlay-title">${isError ? "Error" : isSpam ? "Spam Detected!" : "Genuine Email"}</div>
289	          <div class="ssd-overlay-sub">${isError ? (errorMsg || "Unknown error") : `Confidence: ${data.confidence}%`}</div>
290	        </div>
291	      </div>
292	      ${!isError ? `
293	      <div class="ssd-overlay-bar-wrap">
294	        <div class="ssd-overlay-bar ${isSpam ? "spam" : "genuine"}" style="width: 0%"></div>
295	      </div>` : ""}
296	      ${triggerHTML}
297	    `;
298	
299	    document.body.appendChild(overlay);
300	
301	    // Animate bar
302	    if (!isError) {
303	      requestAnimationFrame(() => {
304	        setTimeout(() => {
305	          const bar = overlay.querySelector(".ssd-overlay-bar");
306	          if (bar) bar.style.width = `${data.confidence}%`;
307	        }, 50);
308	      });
309	    }
310	
311	    // Close button
312	    overlay.querySelector(".ssd-overlay-close").addEventListener("click", () => {
313	      overlay.classList.add("ssd-closing");
314	      setTimeout(() => overlay.remove(), 300);
315	    });
316	
317	    // Auto dismiss after 20s
318	    setTimeout(() => {
319	      const el = document.getElementById(RESULT_ID);
320	      if (el) {
321	        el.classList.add("ssd-closing");
322	        setTimeout(() => el.remove(), 300);
323	      }
324	    }, 20000);
325	  }
326	
327	  // ---- SAVE TO HISTORY ----
328	  function saveToHistory(text, data) {
329	    chrome.storage.local.get(["scanHistory"], (result) => {
330	      const history = result.scanHistory || [];
331	      history.unshift({
332	        text: text.substring(0, 100),
333	        prediction: data.prediction,
334	        confidence: data.confidence,
335	        timestamp: new Date().toLocaleString(),
336	      });
337	      if (history.length > 20) history.pop();
338	      chrome.storage.local.set({ scanHistory: history });
339	    });
340	  }
341	})();
